import { useEffect, useState } from "react";
import { api, getAuthToken } from "../api";

export default function ShopRegister() {
  const [name, setName] = useState("");
  const [area, setArea] = useState("");
  const [rating, setRating] = useState("4.0");
  const [shops, setShops] = useState([]);
  const [error, setError] = useState("");

  const loadShops = async () => {
    if (!getAuthToken()) {
      setError("Please login to manage shops.");
      setShops([]);
      return;
    }

    try {
      setError("");
      const res = await api.get("/shops/");
      setShops(res.data);
    } catch (err) {
      setError("Unable to load shops.");
    }
  };

  useEffect(() => {
    loadShops();
  }, []);

  const createShop = async () => {
    try {
      await api.post("/shops/", { name, area, rating: Number(rating) });
      setName("");
      setArea("");
      setRating("4.0");
      loadShops();
    } catch (err) {
      setError(err.response?.data?.detail || "Unable to create shop.");
    }
  };

  return (
    <div className="page">
      <h2>Shop Registration</h2>
      {error && <p>{error}</p>}
      <input
        placeholder="Shop Name"
        value={name}
        onChange={(e) => setName(e.target.value)}
      />
      <input
        placeholder="Area"
        value={area}
        onChange={(e) => setArea(e.target.value)}
      />
      <input
        placeholder="Rating"
        type="number"
        min="0"
        max="5"
        step="0.1"
        value={rating}
        onChange={(e) => setRating(e.target.value)}
      />
      <button onClick={createShop}>Register Shop</button>

      {shops.map((shop) => (
        <div className="card" key={shop.id}>
          <h3>{shop.name}</h3>
          <p>Area: {shop.area}</p>
          <p>Rating: {shop.rating}</p>
        </div>
      ))}
    </div>
  );
}
